    fn reimport_is_idempotent(case in round_trip_case()) {
        let temp = TempDir::new().unwrap();
        let jsonl_path = temp.path().join("issues.jsonl");
        let export_1 = temp.path().join("after_first.jsonl");
        let export_2 = temp.path().join("after_second.jsonl");

        let original = populate_storage(&case);
        export_to_jsonl(&original, &jsonl_path, &ExportConfig::default())?;

        let mut storage = SqliteStorage::open_memory().unwrap();
        import_from_jsonl(&mut storage, &jsonl_path, &ImportConfig::default(), Some("bd-"))?;
