        import_from_jsonl(&mut storage, &jsonl_path, &ImportConfig::default(), Some("bd-"))?;
        export_to_jsonl(&storage, &export_2, &ExportConfig::default())?;

        prop_assert_eq!(
            fs::read_to_string(&export_1)?,
            fs::read_to_string(&export_2)?,
            "Second import changed database state"
        );
    }
}
```

